fn classify_temp(temp) {
  if temp > 85 {
    return "hot"
  } elif temp > 60 {
    return "nice"
  } else {
    return "cold"
  }
}

show("90 degrees is" classify_temp(90))
show("72 degrees is" classify_temp(72))
show("45 degrees is" classify_temp(45))

fn factorial(n) {
  if n <= 1 {
    return 1
  }
  return n * factorial(n - 1)
}

show("5! =" factorial(5))
show("6! =" factorial(6))
show("10! =" factorial(10))

