steps.code:
blueprint Dog {
  field name
  field breed

  law bark() {
    show("{self.name} says Woof!")
  }

  law describe() {
    show("{self.name} is a {self.breed}")
  }
}

let rex = forge Dog("Rex", "German Shepherd")
rex.bark()
rex.describe()

blueprint BankAccount {
  field owner
  field balance

  law deposit(amount) {
    self.balance = self.balance + amount
    show("{self.owner} deposited ${amount}. Balance: ${self.balance}")
  }

  law withdraw(amount) {
    if amount > self.balance {
      show("Insufficient funds!")
    } else {
      self.balance = self.balance - amount
      show("{self.owner} withdrew ${amount}. Balance: ${self.balance}")
    }
  }
}

let acct = forge BankAccount("Alice", 1000)
acct.deposit(500)
acct.withdraw(200)
acct.withdraw(2000)

blueprint Rectangle {
  field width
  field height

  law area() {
    return self.width * self.height
  }

  law perimeter() {
    return 2 * (self.width + self.height)
  }

  law describe() {
    show("{self.width}x{self.height} rectangle")
    show("  Area: {self.area()}")
    show("  Perimeter: {self.perimeter()}")
  }
}

let r1 = forge Rectangle(5, 3)
let r2 = forge Rectangle(10, 7)

r1.describe()
r2.describe()

show("Total area:" r1.area() + r2.area())

